// WF-03 v6 — SP-Update Payload für Status=Veröffentlicht (defensiv)
// - Liest IG/FB-Post-IDs (oder leer wenn Nodes deaktiviert)
// - Trockenlauf-Stop: wenn beide IDs leer → return [] (kein SP-Update)
// - Item-ID-Auflösung über mehrere mögliche Feldnamen
// - URL-Extractor falls Felder Hyperlink-Objekte sind


function safe(nodeName) {
  try { return $(nodeName).first().json || {}; } catch (e) { return {}; }
}

// --- Post-Responses lesen ---
const igResp = safe('IG_Publish');
const fbResp = safe('FB_Photo');

const igPostId = igResp.id || igResp.post_id || '';
const fbPostId = fbResp.post_id || fbResp.id || '';

// --- Trockenlauf-Stop: keine Posts gemacht → kein SP-Update ---
if (!igPostId && !fbPostId) {
  return [];
}

// --- Item-ID aus Filter-Output robust holen ---
const filterItem = $('FilterKZ').item.json;

const itemId = filterItem.item_id
            || filterItem.id
            || filterItem.Id
            || filterItem.ID
            || filterItem.sp_item_id
            || (filterItem.sp_fields && filterItem.sp_fields.Id)
            || (filterItem.sp_fields && filterItem.sp_fields.ID);

if (!itemId) {
  throw new Error(
    'Kein SP-Item-ID im Filter-Output gefunden. Verfügbare Felder: '
    + Object.keys(filterItem).join(', ')
  );
}

// --- Bestehendes field_13-Log sauber lesen ---
const f = (filterItem.sp_fields) || {};
const existingLog = f.field_13 || '';

// --- Log-Eintrag bauen ---
const now = new Date().toISOString().replace('T', ' ').slice(0, 16);
const logEntry = `\n${now} WF-03 v6: Veröffentlicht — IG ${igPostId || '(deaktiviert)'} / FB ${fbPostId || '(deaktiviert)'}`;

// --- SP-PATCH-Payload zusammenbauen ---
const payload = {
  field_6:  'Veröffentlicht',
  field_13: existingLog + logEntry,
};
if (igPostId) payload.field_12 = igPostId;
// Falls du auch FB-Post-ID in eigenem Feld speichern willst:
// if (fbPostId) payload.field_14 = fbPostId;

return [{
  json: {
    _sp_item_id: itemId,
    payload: payload,
  }
}];

// WF-03 v6 Filter: Karenz-Check + Schedule-Check
const items = $input.all();
const now = new Date();
const KARENZ_HOURS = 24;
const results = [];
const skipped = [];

for (const item of items) {
  const j = item.json;
  const f = j.fields || {};
  const status = f.field_6;
  const modified = j.lastModifiedDateTime || j.Modified;
  const datumRaw = f.Ver_x00f6_ffentlichungsdatum;
  const uhrzeit = (f.field_5 || '09:00').trim();
  const itemId = j.id || j.Ausweis || f.AUSWEIS;
  const title = f.Title || f.Titel || '';

  const reasons = [];
  if (status !== 'Bereit') reasons.push(`status=${status}`);

  // Karenz-Check
  if (modified) {
    const modifiedDate = new Date(modified);
    const hoursSinceModified = (now - modifiedDate) / (1000 * 60 * 60);
    if (hoursSinceModified < KARENZ_HOURS) {
      reasons.push(`karenz_läuft (${hoursSinceModified.toFixed(1)}h von ${KARENZ_HOURS}h)`);
    }
  } else {
    reasons.push('modified_fehlt');
  }

  // Schedule-Check (timezone-aware: uhrzeit = Berlin local time)
  if (datumRaw) {
    const dateOnly = String(datumRaw).split('T')[0];
    const [yyyy, mo, dd] = dateOnly.split('-').map(Number);
    const [hh, mm] = uhrzeit.split(':').map(Number);
    // Berlin: Sommer +02 (Apr-Okt), Winter +01 (Nov-Mär)
    const offsetHours = (mo >= 4 && mo <= 10) ? 2 : 1;
    const scheduledTime = new Date(Date.UTC(yyyy, mo - 1, dd, hh - offsetHours, mm, 0));
    if (isNaN(scheduledTime)) {
      reasons.push(`schedule_invalid (${dateOnly} ${uhrzeit})`);
    } else if (scheduledTime > now) {
      reasons.push(`scheduled_future (Berlin: ${dateOnly} ${uhrzeit})`);
    }
  } else {
    reasons.push('veröffentlichungsdatum_leer');
  }

  // Bild-URLs müssen da sein
  const igUrl = f.field_8 || f.field_9 || '';
  const fbUrl = f.Bild_FB_Dateiname || '';
  if (!igUrl.startsWith('https://')) reasons.push(`IG_keine_url (field_8: "${f.field_8 || ''}" / field_9: "${f.field_9 || ''}")`);
  if (!fbUrl.startsWith('https://')) reasons.push(`Bild_FB_Dateiname_keine_url (wert: "${fbUrl}")`);

  if (reasons.length > 0) {
    skipped.push({ id: itemId, title, status, modified, datum: datumRaw, reasons });
    continue;
  }

  const hashtags = f.field_7 || '';
  const caption = (f.field_10 || '').trim();

  results.push({
    json: {
      item_id: itemId,
      title,
      image_url_ig: igUrl,
      image_url_fb: fbUrl,
      caption,
      hashtags,
      caption_with_hashtags: caption + (hashtags ? '\n\n' + hashtags : ''),
      sp_fields: f,
    }
  });
}

return results.slice(0, 1);
